ucts_table',7),(38,'2025_12_08_195425_add_product_category_id_to_education_posts_table',8),(40,'2025_12_08_212210_create_pages_table',9),(41,'2025_12_09_221529_add_location_id_to_vendor_settings_table',10),(42,'2025_12_12_123840_add_grading_fields_to_vendor_reviews_table',11),(43,'2025_12_12_123850_add_grading_fields_to_brands_table',11),(44,'2025_12_24_120724_create_deals_table',12),(45,'2025_12_24_120727_create_banners_table',12),(46,'2025_12_24_120730_create_scraping_configs_table',12),(47,'2025_12_24_120732_add_status_to_vendor_reviews_table',12),(48,'2025_12_24_121010_add_scraping_fields_to_products_table',12),(49,'2025_12_24_124046_add_vendor_fields_to_vendor_settings_table',13),(50,'2025_12_24_142714_update_deals_table_to_use_brand_id',14),(51,'2025_12_24_142724_add_image_to_banners_table',14),(52,'2025_12_24_143409_update_banners_table_to_use_brand_id',14);
