INSERT INTO `vendor_settings` VALUES (1,1,3,'vendor_banners/pOl7ILeV7yPWLRNyt4coRyIHZaDIeUSzZTz4IXSB.webp',NULL,'vendor_logos/ZgrK0tKLHpoW6MSFvbwp7M8Tk4vYcIaYGR0dIZIp.webp','We offer a comprehensive selection of research peptides, each meticulously synthesized to meet the highest standards of purity and quality. Each batch undergoes rigorous third-party testing with a published lab report. With a focus on purity, transparency, and customer satisfaction, Verified Peptides stands out as a premier supplier for scientific research needs.','support@verifiedpeptides.com',NULL,'https://verifiedpeptides.com/',NULL,NULL,NULL,NULL,NULL,NULL,'2025-12-03 14:43:02','2025-12-24 17:55:51',1,0,0,0,'normal'),(2,2,3,'vendor_banners/kflNJzEMLkrOZ272g2zzwGhfSPlmz4zfgFdVvDSB.webp',NULL,'vendor_logos/svqD7eOSd87n895VcqWJ4V9booPGsShH5cCwFlVh.svg','At Oasis Labs, we know that your research demands more than just a promise of purity — it demands consistency, accountability, and trust. That’s why every peptide we offer is independently lab tested right here in the USA and held to uncompromising standards.\r\n\r\nAs a veteran-owned company, precision isn’t just a goal — it’s how we operate. All orders ship from our fulfillment center in Nevada, ensuring fast, secure delivery every time.\r\n\r\nWe don’t just talk quality. We live it.','info@myoasislabs.com',NULL,'https://myoasislabs.com/',NULL,NULL,NULL,NULL,NULL,NULL,'2025-12-04 13:19:57','2025-12-10 04:53:32',1,0,0,0,'normal'),(3,3,1,'vendor_banners/LJrFEH4BiC0qrTsEwI2JznnaRODy0BCwWedootVd.webp',NULL,'vendor_logos/ui318FJdtgohWZ12tyTBwuOv6EavWNQQpZG23etb.webp','We pride ourselves on offering the most premium peptide supplements available on the market. Each of our products undergoes rigorous quality control, ensuring that only the purest and most effective ingredients make it to our customers. Our dedication to excellence means that you can trust our supplements to support your health and research with uncompromising integrity. Discover the difference that true quality makes, and elevate your experience with Alpha & Omega Peptide’s elite range of products. When it comes to premium peptide supplements, we are the benchmark for superiority and reliability.','info@alphaomegapeptide.com','(888) 453-0711','https://alphaomegapeptide.com/',NULL,NULL,NULL,NULL,NULL,NULL,'2025-12-04 13:51:19','2025-12-10 04:53:57',1,0,0,0,'normal'),(4,4,3,NULL,NULL,'vendor_logos/ecdFIlIBWb7BixjpJfxOVbakQxu4ROXI7CoZGRM6.webp','Buy top-notch quality peptides right away at amazing prices! We are thrilled to bring the most exceptional collection of research-grade peptides for researchers and scientists. Our peptides enable researchers to achieve breakthroughs in the fields of research and analysis.\r\n\r\nTo ensure that researchers have precise and accurate results, we provide them with first- and third-party-tested peptides. With a proper certificate of analysis (COA) and standard quality measures, Purerawz offers peptides that have 99% purity.\r\n\r\nFrom discreet packaging to smooth shipping and in between, we take full responsibility and deliver top-notch peptides at your doorstep. So what are you waiting for? Explore and buy your favourite peptides for better research.','support@purerawz.co','(214)702-9022','https://purerawz.co/',NULL,NULL,NULL,NULL,NULL,NULL,'2025-12-04 14:07:51','2025-12-10 04:53:49',1,0,0,0,'proxy'),(5,5,2,'vendor_banners/L5SCy0WboS3ZBtWhhEIL5ndq0dCc6I49KrJLy9o0.webp',NULL,'vendor_logos/ve1XCsmiTnNcsTdwrNMb3w2iYQNg4mYT1bV8goet.svg','Our organization is committed to supporting scientific progress through the provision of sterile, bug-free and pure compounds optimized for research applications.',NULL,'480-974-4660','https://peptidology.co/',NULL,NULL,NULL,NULL,NULL,NULL,'2025-12-04 15:00:22','2025-12-10 04:53:42',1,0,0,0,'normal'),(6,6,3,'vendor_banners/WEex6mVJ4aCD6Im773I2DwwgQIwJLPErYzRCNSqz.webp',NULL,'vendor_logos/AJ9y9uZ0BGYHJHgRJE9aRgmofRqEGoASTulpKSIb.svg','At Pure Health Peptides, every batch is independently tested in the USA to guarantee unmatched quality. Our third-party testing ensures 99%+ purity and potency, with Certificates of Analysis (COAs) available for every product. Trust in our transparency and commitment to scientific integrity for your research needs.','info@purehealthpeptides.com',NULL,'https://purehealthpeptides.com/',NULL,NULL,NULL,NULL,NULL,NULL,'2025-12-04 15:07:05','2025-12-10 04:53:17',1,0,0,0,'normal'),(7,7,1,'vendor_banners/b0tAcWhRxzANkyYt8KT9O8W8x5Qh8oPEeHZ1Tlgd.webp',NULL,'vendor_logos/PZIYNgF0QrKbZWJ7pHetlBz37kVw2YHU3XjNU2GV.webp','Our peptides are designed to evolve your research to new heights, with the precision, safety, and reliability you’ve come to expect from the very best.',NULL,NULL,'https://www.evolvepeptides.com/',NULL,NULL,NULL,NULL,NULL,NULL,'2025-12-04 15:13:41','2025-12-10 04:53:09',1,0,0,0,'normal'),(8,8,2,'vendor_banners/9wwhQhddDhz9WrN4rJHYS3eCihTNugP7RifgbVDf.webp',NULL,'vendor_logos/dWMMZtngk7tAnOcqbjDif938Asjh44rYUaTTVyeR.webp','All products offered by Amino USA are intended for laboratory research use only. These materials are not for human or veterinary consumption, medical use, diagnostic procedures, or therapeutic applications. Amino USA supplies products exclusively to qualified professionals and licensed research institutions. Statements on this website are for informational and educational purposes only and have not been evaluated by the U.S. Food and Drug Administration (FDA). By accessing this site, you confirm that you are a qualified researcher or institution representative and agree to use all materials in accordance with applicable laws, regulations, and safety guidelines.','info@aminousa.com','(936) 931 8152','https://aminousa.com/',NULL,NULL,NULL,NULL,NULL,NULL,'2025-12-04 17:25:02','2025-12-10 04:53:01',1,0,0,0,'normal'),(9,9,2,NULL,NULL,'vendor_logos/ZGqoeR4EtHAjK8mSHKiHdcc2LoOPkpDlth237HEX.webp','All products on this site are for research and development use only. Products are not for human consumption of any kind. The statements made on this website have not been evaluated by the US Food and Drug Administration. The statements and the products of this company are not intended to diagnose, treat, cure, or prevent any disease. Simple Peptide is not a compounding pharmacy or chemical compounding facility as defined under 503A of the Federal Food, Drug, and Cosmetic Act. Simple Peptide is not an outsourcing facility as defined under 503B of the Federal Food, Drug, and Cosmetic Act. All products are sold for research, laboratory, or analytical purposes only, and are not for human consumption.','support@simplepeptide.com','1-877-711-0702','https://simplepeptide.com/',NULL,NULL,NULL,NULL,NULL,NULL,'2025-12-04 17:28:31','2025-12-24 17:54:21',1,1,1,1,'normal'),(10,10,2,NULL,NULL,NULL,NULL,'info@libertypeptide.com',NULL,'https://libertypeptides.com/',NULL,NULL,NULL,NULL,NULL,NULL,'2025-12-05 21:16:02','2025-12-10 04:52:17',0,0,0,0,'normal'),(11,11,3,NULL,NULL,NULL,'test','info@ripetide',NULL,'https://riptidewellness.com/',NULL,1800,NULL,NULL,NULL,NULL,'2025-12-09 12:08:13','2025-12-24 19:59:41',0,1,1,0,'normal');
